SELECT * FROM(SELECT DISTINCT PGM_YR,ADM_ST_FSA_CD,ADM_CNTY_FSA_CD,TR_NBR,OFR_SCNR_NM,SGNP_NBR,SGNP_TYPE_DESC,SGNP_STYPE_DESC,SGNP_STYPE_AGR_NM,WBP_AGR_NBR,WBP_SEQ_NBR,WBP_ACRG_CROP,WBP_RNT_RT_ACRE,WBP_NCPLD_ACRG,WBP_NCPLD_LGLF,OFR_SCNR_ID,DATA_STAT_CD,CRE_DT,LAST_CHG_DT,LAST_CHG_USER_NM,-- op,ROW_NUMBER() over ( partition by WBP_AGR_NBR,WBP_SEQ_NBR,OFR_SCNR_IDorder by TBL_PRIORITY ASC, LAST_CHG_DT DESC ) AS row_num_partFROM(SELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt45owbp.WBP_AGR_NBR WBP_AGR_NBR,ewt45owbp.WBP_SEQ_NBR WBP_SEQ_NBR,ewt45owbp.WBP_ACRG_CROP WBP_ACRG_CROP,ewt45owbp.WBP_RNT_RT_ACRE WBP_RNT_RT_ACRE,ewt45owbp.WBP_NCPLD_ACRG WBP_NCPLD_ACRG,ewt45owbp.WBP_NCPLD_LGLF WBP_NCPLD_LGLF,ewt45owbp.OFR_SCNR_ID OFR_SCNR_ID,ewt45owbp.DATA_STAT_CD DATA_STAT_CD,ewt45owbp.CRE_DT CRE_DT,ewt45owbp.LAST_CHG_DT LAST_CHG_DT,ewt45owbp.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,1 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT45OWBP LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT45OWBP.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)--WHERE __CDC_OPERATION <> 'D'
UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt45owbp.WBP_AGR_NBR WBP_AGR_NBR,ewt45owbp.WBP_SEQ_NBR WBP_SEQ_NBR,ewt45owbp.WBP_ACRG_CROP WBP_ACRG_CROP,ewt45owbp.WBP_RNT_RT_ACRE WBP_RNT_RT_ACRE,ewt45owbp.WBP_NCPLD_ACRG WBP_NCPLD_ACRG,ewt45owbp.WBP_NCPLD_LGLF WBP_NCPLD_LGLF,ewt45owbp.OFR_SCNR_ID OFR_SCNR_ID,ewt45owbp.DATA_STAT_CD DATA_STAT_CD,ewt45owbp.CRE_DT CRE_DT,ewt45owbp.LAST_CHG_DT LAST_CHG_DT,ewt45owbp.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,2 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT40OFRSC JOIN "fsa-prod-cnsv".EWT45OWBP ON (EWT40OFRSC.OFR_SCNR_ID = EWT45OWBP.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)--WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt45owbp.WBP_AGR_NBR WBP_AGR_NBR,ewt45owbp.WBP_SEQ_NBR WBP_SEQ_NBR,ewt45owbp.WBP_ACRG_CROP WBP_ACRG_CROP,ewt45owbp.WBP_RNT_RT_ACRE WBP_RNT_RT_ACRE,ewt45owbp.WBP_NCPLD_ACRG WBP_NCPLD_ACRG,ewt45owbp.WBP_NCPLD_LGLF WBP_NCPLD_LGLF,ewt45owbp.OFR_SCNR_ID OFR_SCNR_ID,ewt45owbp.DATA_STAT_CD DATA_STAT_CD,ewt45owbp.CRE_DT CRE_DT,ewt45owbp.LAST_CHG_DT LAST_CHG_DT,ewt45owbp.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,3 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT14SGNP LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT14SGNP.SGNP_ID = EWT40OFRSC.SGNP_ID) JOIN "fsa-prod-cnsv".EWT45OWBP ON (EWT40OFRSC.OFR_SCNR_ID = EWT45OWBP.OFR_SCNR_ID)--WHERE __CDC_OPERATION <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1AND (
 (COALESCE(CAST(CRE_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
    AND
    (COALESCE(CAST(LAST_CHG_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
)

UNIONSELECT DISTINCTNULL PGM_YR,NULL ADM_ST_FSA_CD,NULL ADM_CNTY_FSA_CD,NULL TR_NBR,NULL OFR_SCNR_NM,NULL SGNP_NBR,NULL SGNP_TYPE_DESC,NULL SGNP_STYPE_DESC,NULL SGNP_STYPE_AGR_NM,ewt45owbp.WBP_AGR_NBR WBP_AGR_NBR,ewt45owbp.WBP_SEQ_NBR WBP_SEQ_NBR,ewt45owbp.WBP_ACRG_CROP WBP_ACRG_CROP,ewt45owbp.WBP_RNT_RT_ACRE WBP_RNT_RT_ACRE,ewt45owbp.WBP_NCPLD_ACRG WBP_NCPLD_ACRG,ewt45owbp.WBP_NCPLD_LGLF WBP_NCPLD_LGLF,ewt45owbp.OFR_SCNR_ID OFR_SCNR_ID,ewt45owbp.DATA_STAT_CD DATA_STAT_CD,ewt45owbp.CRE_DT CRE_DT,ewt45owbp.LAST_CHG_DT LAST_CHG_DT,ewt45owbp.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,1 AS row_num_partFROM "fsa-prod-cnsv".ewt45owbp--WHERE __CDC_OPERATION = 'D'